Passing tests: 4 (plus 1 todo)
Recent changes: Green phase implemented neighbor counting using a Set for O(1) lookup and survival rule (live cells with 2 or 3 neighbors survive). No reproduction logic yet.

Current implementation:
```typescript
export function nextGeneration(
  liveCells: [number, number][],
): [number, number][] {
  const liveSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));

  const survivors: [number, number][] = [];

  for (const [x, y] of liveCells) {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(`${x + dx},${y + dy}`)) count++;
      }
    }
    if (count === 2 || count === 3) {
      survivors.push([x, y]);
    }
  }

  return survivors;
}
```

